import React from "react";
import { ArrowLeft } from "lucide-react";

export default function AddMoneyOptionsScreen({ onBack, onSelectOption, darkMode }) {
  const options = [
    { id: 1, title: "Bank Transfer" },
    { id: 2, title: "Debit/Credit Card" },
    { id: 3, title: "USSD" },
  ];

  return (
    <div
      className={`min-h-screen px-5 pt-6 pb-24 ${
        darkMode ? "bg-gray-900" : "bg-[#f4f6fb]"
      }`}
    >
      {/* Header */}
      <div className="flex items-center gap-3 mb-8">
        <button onClick={onBack}>
          <ArrowLeft
            className={`w-6 h-6 ${darkMode ? "text-gray-300" : "text-gray-700"}`}
          />
        </button>
        <h1 className={`text-xl font-semibold ${darkMode ? "text-white" : "text-gray-900"}`}>
          Add Money
        </h1>
      </div>

      {/* Options */}
      <div className="space-y-4">
        {options.map((opt) => (
          <button
            key={opt.id}
            onClick={() => onSelectOption(opt)}
            className={`w-full rounded-xl p-4 shadow-sm text-left active:scale-[0.98] transition ${
              darkMode ? "bg-gray-800 text-white shadow-gray-700" : "bg-white text-gray-900 shadow-sm"
            }`}
          >
            {opt.title}
          </button>
        ))}
      </div>
    </div>
  );
}
